@namespace Lumeo

<div class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
    <div aria-hidden="true" class="pointer-events-none absolute inset-0 z-10" style="@OverlayStyle">
    </div>
</div>

@code {
    /// <summary>Text tiled as the repeating watermark, rendered via a rotated SVG
    /// mask over the host's current text color. Ignored when <see cref="Image"/> is set.</summary>
    [Parameter] public string? Text { get; set; }

    /// <summary>Optional image URL to tile as the watermark instead of <see cref="Text"/>.
    /// When set, the image is repeated edge-to-edge; <see cref="ImageWidth"/>/<see cref="ImageHeight"/>
    /// control each tile's size and <see cref="Opacity"/> dims it. Takes precedence over
    /// <see cref="Text"/> when both are provided.</summary>
    [Parameter] public string? Image { get; set; }

    /// <summary>Tile width in px for the <see cref="Image"/> watermark. Default 120.</summary>
    [Parameter] public int ImageWidth { get; set; } = 120;

    /// <summary>Tile height in px for the <see cref="Image"/> watermark. Default 64.</summary>
    [Parameter] public int ImageHeight { get; set; } = 64;

    /// <summary>The content the watermark overlay is stamped on top of.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Rotation in degrees applied to the text watermark tile. Defaults to -22.</summary>
    [Parameter] public int Rotation { get; set; } = -22;

    /// <summary>Spacing in pixels between repeated text watermark tiles. Defaults to 100.</summary>
    [Parameter] public int Gap { get; set; } = 100;

    /// <summary>Font size in pixels of the text watermark. Defaults to 14.</summary>
    [Parameter] public int FontSize { get; set; } = 14;

    /// <summary>Opacity of the watermark overlay, from 0 to 1. Defaults to 0.1.</summary>
    [Parameter] public double Opacity { get; set; } = 0.1;

    /// <summary>Additional CSS classes merged onto the outer wrapper.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Captures unmatched attributes and applies them to the outer wrapper.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("relative", Class);

    // Image mode wins when an Image URL is supplied; otherwise fall back to the
    // generated SVG text watermark (empty when no Text either).
    //
    // Text mode paints the SVG as a CSS mask over `background-color: currentColor`
    // rather than as a background-image. `currentColor` inside a background-image
    // data-URI SVG cannot reach the host element's color — it resolves to the
    // isolated SVG document's default (black), so the watermark was invisible/wrong
    // in dark mode. A mask only uses the SVG's alpha channel (the text's
    // `opacity` dims it), while the visible color comes from the overlay div's own
    // `background-color: currentColor`, which DOES inherit the host theme color.
    private string OverlayStyle => !string.IsNullOrEmpty(Image)
        ? ImageOverlayStyle
        : FormattableString.Invariant($"-webkit-mask-image: url('data:image/svg+xml,{EncodedSvg}'); mask-image: url('data:image/svg+xml,{EncodedSvg}'); -webkit-mask-repeat: repeat; mask-repeat: repeat; background-color: currentColor;");

    private string ImageOverlayStyle
    {
        get
        {
            // Tile the image at its own ImageWidth × ImageHeight, repeated edge to
            // edge, with the whole layer dimmed by Opacity. (Gap is text-mode tile
            // spacing — a non-distorting CSS image gap isn't expressible in a single
            // background, so it doesn't apply here.) Escape any " in the URL.
            var safeUrl = Image!.Replace("\"", "%22");
            var w = Math.Max(ImageWidth, 1);
            var h = Math.Max(ImageHeight, 1);
            // FormattableString.Invariant: Opacity is a double — comma-decimal
            // locales would emit an invalid value otherwise (mirrors the SVG path).
            return FormattableString.Invariant(
                $"background-image: url(\"{safeUrl}\"); background-repeat: repeat; background-size: {w}px {h}px; opacity: {Opacity};");
        }
    }

    private string EncodedSvg
    {
        get
        {
            if (string.IsNullOrEmpty(Text)) return "";

            var textLength = Text.Length * FontSize * 0.6;
            var svgWidth = Math.Max(Gap + textLength, 200);
            var svgHeight = Math.Max(Gap + FontSize * 2, 100);

            // FormattableString.Invariant: svgWidth/svgHeight are doubles — with
            // CurrentCulture interpolation, comma-decimal locales emitted
            // width="236,8" / rotate(-22 118,4 50), invalid SVG → no watermark.
            // (Single interpolated string: concatenating $-strings degrades to
            // string and can't bind to the FormattableString overload.)
            //
            // fill is a solid opaque color (not currentColor): this SVG is used as a
            // CSS mask, so only its alpha matters — the theme color comes from the
            // overlay div's `background-color: currentColor` (see OverlayStyle). The
            // text's `opacity` carries through the mask alpha to dim the watermark.
            var svg = FormattableString.Invariant($"<svg xmlns=\"http://www.w3.org/2000/svg\" width=\"{svgWidth}\" height=\"{svgHeight}\"><text x=\"50%\" y=\"50%\" text-anchor=\"middle\" dominant-baseline=\"middle\" font-size=\"{FontSize}\" fill=\"#000\" opacity=\"{Opacity}\" transform=\"rotate({Rotation} {svgWidth / 2} {svgHeight / 2})\">{System.Net.WebUtility.HtmlEncode(Text)}</text></svg>");

            return Uri.EscapeDataString(svg);
        }
    }
}
